void solve(int CASE)
{
	ll n, m; cin >> n >> m;
	var res = Math::division_block(n);
	res.pb(n + 1);
	if (res.back() <= m)res.pb(m + 1);
	ll ans = 0;
	fa(i, 0, vs(res)) {
		if (res[i] > m)break;
		ll len = min(m + 1, res[i + 1]) - res[i];
		ll d = -n / res[i];
		ll a1 = n % res[i];
		len = (len % mod + mod) % mod;
		d = (d % mod + mod) % mod;
		a1 = (a1 % mod + mod) % mod;

		ll sum = a1 * len % mod + len * (len - 1) % mod * d % mod * Math::inv(2, mod) % mod;
		sum %= mod;
		ans += sum;
		ans %= mod;

		//debug(n / res[i], res[i], n % res[i]); // n = k * x + r
	}
	cout << ans << endl;
	return;
}
